import React, {useEffect, useMemo} from 'react';
import {type FieldValues, useWatch} from 'react-hook-form';
import type {ICombined, UseFieldLogicElementProps} from "@lmb-it/kitsconcerto-types";
import {Flex} from "../../../../_compat";
import KitsContainer from "../../../../form/helpers/FormContainer";
import {FormRenderer} from "../../FormRenderer";

/**
 * Combined element: groups multiple child inputs under one logical field.
 *
 * - Renders a single KitsContainer with one label and one validation error.
 * - Child elements render with `attached: true` (no individual containers/labels).
 * - The parent's value is computed from child values via the `output` template.
 */
export const CombinedElement = <T extends FieldValues>({
                                                           element,
                                                           control,
                                                           getValues,
                                                           groupField,
                                                           focusedField,
                                                           setFocusedField,
                                                           fieldLogic,
                                                       }: UseFieldLogicElementProps<T>) => {

    const {
        isShown,
        label,
        helperText,
        field,
        fieldState,
        isRequired,
        isDisabled,
        formContext,
        hideError,
    } = fieldLogic;

    const combinedElement = element as ICombined<T>;
    const {grid, output, elements: childElements} = combinedElement;

    // Extract child field IDs for watching
    const childIds = useMemo(() =>
            childElements.map(el => el.id as string),
        [childElements]
    );

    // Watch all child field values
    const childValues = useWatch({
        name: childIds as any,
        control,
    });

    // Compute and sync the output value whenever child values change
    useEffect(() => {
        const outputTokens = output.trim().split(/\s+/);
        let computedValue: any;

        if (outputTokens.length === 1) {
            // Single token — map to that child's value directly
            const childIndex = childIds.indexOf(outputTokens[0]);
            computedValue = childIndex >= 0 ? childValues[childIndex] : undefined;
        } else {
            // Multi-token — concatenate child values with spaces
            computedValue = outputTokens
                .map(token => {
                    const childIndex = childIds.indexOf(token);
                    return childIndex >= 0 ? (childValues[childIndex] ?? '') : '';
                })
                .filter(v => v !== '')
                .join(' ');
        }

        // Only update if the value has actually changed
        const currentValue = formContext.getValues(field.name);
        if (currentValue !== computedValue) {
            formContext.setValue(field.name, computedValue, {
                shouldValidate: true,
                shouldDirty: true,
            });
        }
    }, [childValues, output, childIds, field.name, formContext]);

    // Prepare child elements with attached=true to strip their containers/labels
    const attachedElements = useMemo(() =>
            childElements.map(el => ({
                ...el,
                // Remove label and schema from children — parent handles these
                label: undefined,
                schema: undefined,
                hideError: true,
                attached: true,
            })),
        [childElements]
    );

    if (!isShown) {
        return null;
    }

    return (
        <KitsContainer
            id={element.id as string}
            label={label}
            required={isRequired}
            errors={fieldState.error?.message}
            invalid={fieldState.invalid}
            helperText={helperText}
            hideError={hideError}
            disabled={isDisabled}
        >
            <Flex w="full" gap={8} alignItems="center">
                <FormRenderer
                    elements={attachedElements}
                    control={control}
                    getValues={getValues}
                    groupField={groupField}
                    focusedField={focusedField}
                    setFocusedField={setFocusedField!}
                    grid={{
                        columns: 12,
                        columnGap: 8,
                        rowGap: 0,
                        colSpan: 12,
                        ...grid,
                    } as any}
                />
            </Flex>
        </KitsContainer>
    );
};

export default CombinedElement;
